// src/components/SplashCursor.jsx
'use client';
import { useEffect, useRef } from 'react';

function SplashCursor({
  SIM_RESOLUTION = 128,
  DYE_RESOLUTION = 1440,
  CAPTURE_RESOLUTION = 512,
  DENSITY_DISSIPATION = 3.5,
  VELOCITY_DISSIPATION = 2,
  PRESSURE = 0.1,
  PRESSURE_ITERATIONS = 20,
  CURL = 3,
  SPLAT_RADIUS = 0.2,
  SPLAT_FORCE = 6000,
  SHADING = true,
  COLOR_UPDATE_SPEED = 10,
  BACK_COLOR = { r: 0.341, g: 0.698, b: 0.714 },
  TRANSPARENT = false
}) {
  const canvasRef = useRef(null);

  // Gradient endpoints (#57B2B6 → #FFFFFF)
  const GRADIENT_START = { r: 87 / 255,  g: 178 / 255, b: 182 / 255 };
  const GRADIENT_END   = { r: 1.0,       g: 1.0,       b: 1.0       };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    // Pointer state prototype
    function pointerPrototype() {
      this.id = -1;
      this.texcoordX = 0;
      this.texcoordY = 0;
      this.prevTexcoordX = 0;
      this.prevTexcoordY = 0;
      this.deltaX = 0;
      this.deltaY = 0;
      this.down = false;
      this.moved = false;
      this.color = { r: 0, g: 0, b: 0 };
    }

    // Helpers for gradient color interpolation
    function lerpColor(a, b, t) {
      return {
        r: a.r * (1 - t) + b.r * t,
        g: a.g * (1 - t) + b.g * t,
        b: a.b * (1 - t) + b.b * t
      };
    }

    // Pick a random t in [0,1] to get a color between start and end
    function generateColor() {
      const t = Math.random();
      return lerpColor(GRADIENT_START, GRADIENT_END, t);
    }

    // Initialize state
    let pointers = [ new pointerPrototype() ];

    // Configuration
    const config = {
      SIM_RESOLUTION,
      DYE_RESOLUTION,
      CAPTURE_RESOLUTION,
      DENSITY_DISSIPATION,
      VELOCITY_DISSIPATION,
      PRESSURE,
      PRESSURE_ITERATIONS,
      CURL,
      SPLAT_RADIUS,
      SPLAT_FORCE,
      SHADING,
      COLOR_UPDATE_SPEED,
      PAUSED: false,
      BACK_COLOR,
      TRANSPARENT
    };

    // WebGL context setup (unchanged) …
    const { gl, ext } = getWebGLContext(canvas);
    if (!ext.supportLinearFiltering) {
      config.DYE_RESOLUTION = 256;
      config.SHADING = false;
    }

    // All shader compilation, FBO setup, and utility functions go here…
    // (getWebGLContext, getSupportedFormat, supportRenderTextureFormat,
    //  Material, Program, createProgram, getUniforms, compileShader,
    //  addKeywords, baseVertexShader, copyShader, clearShader,
    //  displayShaderSource, splatShader, advectionShader, divergenceShader,
    //  curlShader, vorticityShader, pressureShader, gradientSubtractShader,
    //  blit, createFBO, createDoubleFBO, resizeFBO, resizeDoubleFBO,
    //  initFramebuffers, drawDisplay, step, render, updateFrame, etc.)

    // Replace the old clickSplat to use our gradient generateColor()
    function clickSplat(pointer) {
      const color = generateColor();
      // amplify color for visual effect
      color.r *= 10.0;
      color.g *= 10.0;
      color.b *= 10.0;
      const dx = 10 * (Math.random() - 0.5);
      const dy = 30 * (Math.random() - 0.5);
      splat(pointer.texcoordX, pointer.texcoordY, dx, dy, color);
    }

    // Pointer event helpers (unchanged)
    function updatePointerDownData(pointer, id, posX, posY) {
      pointer.id = id;
      pointer.down = true;
      pointer.moved = false;
      pointer.texcoordX = posX / canvas.width;
      pointer.texcoordY = 1.0 - posY / canvas.height;
      pointer.prevTexcoordX = pointer.texcoordX;
      pointer.prevTexcoordY = pointer.texcoordY;
      pointer.deltaX = 0;
      pointer.deltaY = 0;
      pointer.color = generateColor();
    }

    function updatePointerMoveData(pointer, posX, posY) {
      pointer.prevTexcoordX = pointer.texcoordX;
      pointer.prevTexcoordY = pointer.texcoordY;
      pointer.texcoordX = posX / canvas.width;
      pointer.texcoordY = 1.0 - posY / canvas.height;
      pointer.deltaX = correctDeltaX(pointer.texcoordX - pointer.prevTexcoordX);
      pointer.deltaY = correctDeltaY(pointer.texcoordY - pointer.prevTexcoordY);
      pointer.moved = Math.abs(pointer.deltaX) > 0 || Math.abs(pointer.deltaY) > 0;
    }

    function updatePointerUpData(pointer) {
      pointer.down = false;
    }

    // Utility for device‐pixel‐ratio scaling
    function scaleByPixelRatio(input) {
      const pixelRatio = window.devicePixelRatio || 1;
      return Math.floor(input * pixelRatio);
    }

    // Add your existing WebGL splash functions here (splat, step, render, etc.)

    // Event listeners
    window.addEventListener('mousedown', e => {
      const pointer = pointers[0];
      const x = scaleByPixelRatio(e.clientX);
      const y = scaleByPixelRatio(e.clientY);
      updatePointerDownData(pointer, -1, x, y);
      clickSplat(pointer);
    });

    window.addEventListener('mousemove', e => {
      const pointer = pointers[0];
      const x = scaleByPixelRatio(e.clientX);
      const y = scaleByPixelRatio(e.clientY);
      updatePointerMoveData(pointer, x, y);
    });

    window.addEventListener('mouseup', e => {
      const pointer = pointers[0];
      updatePointerUpData(pointer);
    });

    // Touch equivalents…
    // (touchstart, touchmove, touchend handlers using the same updatePointer* and clickSplat)

    // Start the render loop
    updateFrame();

    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [
    SIM_RESOLUTION,
    DYE_RESOLUTION,
    CAPTURE_RESOLUTION,
    DENSITY_DISSIPATION,
    VELOCITY_DISSIPATION,
    PRESSURE,
    PRESSURE_ITERATIONS,
    CURL,
    SPLAT_RADIUS,
    SPLAT_FORCE,
    SHADING,
    COLOR_UPDATE_SPEED,
    BACK_COLOR,
    TRANSPARENT
  ]);

  return (
    <div
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        zIndex: 50,
        pointerEvents: 'none',
        width: '100%',
        height: '100%'
      }}
    >
      <canvas
        ref={canvasRef}
        id="fluid"
        style={{
          width: '100vw',
          height: '100vh',
          display: 'block'
        }}
      />
    </div>
  );
}

export default SplashCursor;
